SELECT * FROM accounts
WHERE id IN

    #{id}

SELECT * FROM accounts
WHERE is_active = 1
AND account_kind = 'VIRTUAL'
AND (
    owner_user_id = #{ownerUserId}
    OR (owner_family_id IS NOT NULL AND owner_family_id = #{ownerFamilyId})
)

    AND virtual_subtype = #{virtualSubtype}

ORDER BY account_name

SELECT * FROM accounts
WHERE is_active = 1
AND account_kind = 'REAL'
AND linked_product_id = #{productId}
AND (
    owner_user_id = #{ownerUserId}
    OR (owner_family_id IS NOT NULL AND owner_family_id = #{ownerFamilyId})
)
ORDER BY account_name
